    while(T--) {
        int N; cin>>N;
        vector<long long> a(N);
        for(int i=0;i<N;++i) cin>>a[i];
        sort(a.begin(), a.end());
        for(int i=0;i<N;++i) {
            if(i) cout<<' ';
            cout<<a[i];
        }
        cout<<'\n';
    }
