const T = input[idx++];
let outputs = [];
for (let t = 0; t < T; ++t) {
  const N = input[idx++];
  const arr = input.slice(idx, idx + N);
  idx += N;
  arr.sort((a, b) => a - b);
  outputs.push(arr.join(' '));
}
